import random, re, json, glob
from datetime import datetime
import numpy as np
import pandas as pd
import matplotlib.pyplot as plt
import matplotlib.gridspec as gridspec
import seaborn as sns

GLOBAL_SEED = 42
random.seed(GLOBAL_SEED)
np.random.seed(GLOBAL_SEED)
sns.set_theme(style='whitegrid')

try:
    import kaggle_benchmarks as kbench
    KAGGLE_ENV = True
    print(f'✅ kaggle_benchmarks loaded — Model: {kbench.llm}')
except ModuleNotFoundError:
    KAGGLE_ENV = False
    print('ℹ️  kaggle_benchmarks not found — loading local mock')

    class _Assertions:
        def assert_true(self, condition, expectation=''):
            pass

    class _MockLLM:
        COLLAPSE_PROBS = {
            'number_repetition': {1:0.48, 5:0.03, 10:0.01, 25:0.00, 50:0.00, 100:0.00},
            'word_repetition':   {1:0.00, 5:0.00, 10:0.00, 25:0.00, 50:0.00, 100:0.00},
            'symbol_repetition': {1:0.00, 5:0.00, 10:0.00, 25:0.00, 50:0.00, 100:0.00},
            'noise':             {1:0.00, 5:0.00, 10:0.00, 25:0.00, 50:0.00, 100:0.00},
        }
        POSITION_PENALTY = {'beginning': 0.0, 'middle': 0.01, 'end': 0.06}
        def prompt(self, text, **kw):
            all_amounts = [int(x) for x in re.findall(r'\b\d+\b', text)]
            if not all_amounts: return '0'
            dtype = kw.get('_distractor_type', 'noise')
            level = kw.get('_level', 1)
            pos   = kw.get('_position', 'beginning')
            tbl   = self.COLLAPSE_PROBS.get(dtype, self.COLLAPSE_PROBS['noise'])
            cl    = min(tbl.keys(), key=lambda k: abs(k - level))
            p_fail = tbl[cl] + self.POSITION_PENALTY.get(pos, 0)
            if random.random() < p_fail and len(all_amounts) > 1:
                return str(random.choice(all_amounts[1:]))
            return str(all_amounts[0])

    class _Results:
        def __init__(self, r, resp): self._r=r; self._resp=resp
        def as_dataframe(self):
            return pd.DataFrame({'result': self._r, 'response': self._resp})

    class _Task:
        def __init__(self, fn, name): self._fn=fn; self.name=name
        def evaluate(self, llm, evaluation_data):
            if isinstance(llm, list): llm = llm[0]
            rows = evaluation_data.to_dict('records')
            results, responses = [], []
            for row in rows:
                noisy  = row.get('noisy_text', '')
                dtype  = row.get('distractor_type', 'noise')
                level  = row.get('level', 1)
                true_a = row.get('true_answer', 0)
                pos    = row.get('target_position', 'beginning')
                if isinstance(llm, _MockLLM):
                    resp = llm.prompt(noisy, _distractor_type=dtype,
                                      _level=level, _true_answer=true_a, _position=pos)
                else:
                    resp = llm.prompt(noisy)
                matches   = re.findall(r'\b\d+\b', str(resp))
                predicted = int(matches[0]) if matches else None
                results.append(predicted == true_a)
                responses.append(resp)
            return _Results(results, responses)

    class _KBench:
        def __init__(self):
            self.assertions = _Assertions()
            self.llm        = _MockLLM()
        def task(self, name):
            def decorator(fn):
                t = _Task(fn, name); fn.evaluate = t.evaluate; return fn
            return decorator

    kbench = _KBench()
    print('✅ Mock ready')

